document.addEventListener("DOMContentLoaded",function(){const siteContact={email:"malakakatlego67@gmail.com",phone:"+27 76 913 5144",linkedin:"https://www.linkedin.com/in/katlego-jeffrey-malaka",github:"https://github.com/KJMalaka",instagram:"https://www.instagram.com/katlego_malaka67",location:"Cape Town, South Africa",status:"Available for Internships"};const elEmail=document.getElementById("contactEmail");const elPhone=document.getElementById("contactPhone");const elLocation=document.getElementById("contactLocation");const elStatus=document.getElementById("contactStatus");const elLinkedIn=document.getElementById("contactLinkedIn");const elGitHub=document.getElementById("contactGitHub");const elInstagram=document.getElementById("contactInstagram");if(elEmail){elEmail.textContent=siteContact.email;elEmail.setAttribute("href","mailto:"+siteContact.email)}if(elPhone){elPhone.textContent=siteContact.phone;elPhone.setAttribute("href","tel:"+siteContact.phone.replace(/\s+/g,""))}if(elLocation)elLocation.textContent=siteContact.location;if(elStatus)elStatus.textContent=siteContact.status;if(elLinkedIn)elLinkedIn.setAttribute("href",siteContact.linkedin);if(elGitHub)elGitHub.setAttribute("href",siteContact.github);if(elInstagram)elInstagram.setAttribute("href",siteContact.instagram);const emailCta=document.getElementById("emailCta");const callCta=document.getElementById("callCta");if(emailCta&&siteContact.email){emailCta.setAttribute("href","mailto:"+siteContact.email)}if(callCta&&siteContact.phone){callCta.setAttribute("href","tel:"+siteContact.phone.replace(/\s+/g,""))}const copyBtn=document.getElementById("copyEmailBtn");if(copyBtn&&siteContact.email){copyBtn.addEventListener("click",async e=>{e.preventDefault();const text=siteContact.email;try{await navigator.clipboard.writeText(text);const original=copyBtn.textContent;copyBtn.textContent="Copied!";copyBtn.disabled=true;setTimeout(()=>{copyBtn.textContent=original;copyBtn.disabled=false},1800)}catch(err){const temp=document.createElement("textarea");temp.value=text;document.body.appendChild(temp);temp.select();try{document.execCommand("copy");alert("Email copied to clipboard")}catch(e){prompt("Copy this email:",text)}temp.remove()}})}const viewProjectsBtn=document.getElementById("view-projects-btn");const getInTouchBtn=document.getElementById("get-in-touch-btn");if(viewProjectsBtn){viewProjectsBtn.addEventListener("click",()=>{document.getElementById("projects")?.scrollIntoView({behavior:"smooth"})})}if(getInTouchBtn){getInTouchBtn.addEventListener("click",()=>{document.getElementById("contact")?.scrollIntoView({behavior:"smooth"})})}const form=document.getElementById("contact-form");if(form){form.addEventListener("submit",e=>{e.preventDefault();alert("Thank you for your message! I will get back to you soon.");form.reset()})}const skills=[{name:"HTML & CSS",level:90},{name:"JavaScript",level:85},{name:"React",level:80},{name:"Node.js",level:75},{name:"Python",level:80},{name:"SQL & Databases",level:75},{name:"Git & GitHub",level:85},{name:"UI/UX Design",level:70}];const skillsGrid=document.getElementById("skillsGrid");if(skillsGrid){skills.forEach(s=>{const card=document.createElement("div");card.className="skill-card card";const name=document.createElement("div");name.className="skill-name";name.textContent=s.name;const bar=document.createElement("div");bar.className="skill-bar";const fill=document.createElement("div");fill.className="skill-fill";fill.style.width="0%";bar.appendChild(fill);card.appendChild(name);card.appendChild(bar);skillsGrid.appendChild(card);setTimeout(()=>{fill.style.width=s.level+"%"},150)})}const statNumbers=document.querySelectorAll(".stat-number");const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.style.opacity="1";entry.target.style.transform="translateY(0)"}})},{threshold:.1});statNumbers.forEach(stat=>{stat.style.opacity="0";stat.style.transform="translateY(20px)";stat.style.transition="all 0.6s ease";observer.observe(stat)});const skillCards=document.querySelectorAll(".skill-card");const skillObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){const fill=entry.target.querySelector(".skill-fill");const targetWidth=fill.style.width;fill.style.width="0%";setTimeout(()=>{fill.style.width=targetWidth},100)}})},{threshold:.2});skillCards.forEach(card=>{skillObserver.observe(card)});document.querySelectorAll(".project-links a").forEach(a=>{a.addEventListener("click",e=>{const href=a.getAttribute("href");if(!href||href.trim()==="#"){e.preventDefault();alert("Link not set yet. Replace with your project URL.")}})});document.querySelectorAll(".card").forEach(card=>{card.addEventListener("mouseenter",function(){this.style.transform="translateY(-4px)"});card.addEventListener("mouseleave",function(){this.style.transform="translateY(0)"})});document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener("click",function(e){const href=this.getAttribute("href");if(href!=="#"){e.preventDefault();const target=document.querySelector(href);if(target){target.scrollIntoView({behavior:"smooth",block:"start"})}}})});document.body.style.opacity="0";setTimeout(()=>{document.body.style.transition="opacity 0.5s ease";document.body.style.opacity="1"},100);console.log("Portfolio loaded successfully! ✨")});